import { moduleMetadata } from '@storybook/angular';
import { PfHighlightComponent } from './highlight.component';
import { PfInputComponent } from '../input/input.component';
const meta = {
    title: 'Composants/Highlight',
    component: PfHighlightComponent,
    tags: ['autodocs'],
    parameters: {
        docs: {
            description: {
                component: "Surlignage basé sur l'élément `<mark>` natif HTML5. Mode direct (tout est surligné) ou avec `query` (seules les occurrences sont surlignées).",
            },
        },
    },
    decorators: [
        moduleMetadata({ imports: [PfHighlightComponent, PfInputComponent] }),
    ],
};
export default meta;
export const Direct = {
    args: { text: 'important' },
    render: ({ text }) => ({
        props: { text },
        template: `<p>Le mot <pf-highlight [text]="text"></pf-highlight> est mis en évidence.</p>`,
    }),
};
export const WithQuery = {
    args: {
        text: 'Direction des affaires maritimes - Service de la navigation maritime côtière',
        query: 'maritime',
    },
    render: ({ text, query }) => ({
        props: { text, query },
        template: `<p><pf-highlight [text]="text" [query]="query"></pf-highlight></p>`,
    }),
};
export const SearchResults = {
    render: () => ({
        props: {
            query: 'permis',
            results: [
                'Permis bateau côtier',
                'Demande de permis hauturier',
                "Renouvellement d'un permis fluvial",
                "Inscription d'un navire",
            ],
        },
        template: `
      <div style="display: flex; flex-direction: column; gap: 12px; max-width: 480px;">
        <pf-input label="Rechercher" [value]="query" (valueChange)="query = $event" placeholder="Saisir une recherche…"></pf-input>
        <ul style="margin: 0; padding-left: 20px;">
          @for (r of results; track r) {
            <li><pf-highlight [text]="r" [query]="query"></pf-highlight></li>
          }
        </ul>
      </div>
    `,
    }),
};
